export const completion = () => {
  const total = MODULES.length;
  const done = MODULES.filter(m => m.status === 'done').length;
  const inProgress = MODULES.filter(m => m.status === 'in-progress').length;
  return { total, done, inProgress, planned: total - done - inProgress, percent: Math.round((done / total) * 100) };
};

export const modulesBySubjek = (s: string) => MODULES.filter(m => m.subjek === s);
export const modulesByDomain = (d: ModuleL3['domain']) => MODULES.filter(m => m.domain === d);
export const findModuleByRoute = (route: string) => MODULES.find(m => m.route === route);
export const findModuleByCode = (code: string) => MODULES.find(m => m.code === code);
